120	export function resolveIrcAccount(params: {
121	  cfg: CoreConfig;
122	  accountId?: string | null;
123	}): ResolvedIrcAccount {
124	  const hasExplicitAccountId = Boolean(params.accountId?.trim());
125	  const baseEnabled = params.cfg.channels?.irc?.enabled !== false;
126	
127	  const resolve = (accountId: string) => {
128	    const merged = mergeIrcAccountConfig(params.cfg, accountId);
129	    const accountEnabled = merged.enabled !== false;
130	    const enabled = baseEnabled && accountEnabled;
131	
132	    const tls =
133	      typeof merged.tls === "boolean"
134	        ? merged.tls
135	        : accountId === DEFAULT_ACCOUNT_ID && process.env.IRC_TLS
136	          ? parseTruthy(process.env.IRC_TLS)
137	          : true;
138	
139	    const envPort =
140	      accountId === DEFAULT_ACCOUNT_ID ? parseIntEnv(process.env.IRC_PORT) : undefined;
141	    const port = merged.port ?? envPort ?? (tls ? 6697 : 6667);
142	    const envChannels =
143	      accountId === DEFAULT_ACCOUNT_ID
144	        ? parseOptionalDelimitedEntries(process.env.IRC_CHANNELS)
145	        : undefined;
146	
147	    const host = (
148	      merged.host?.trim() ||
149	      (accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_HOST?.trim() : "") ||
150	      ""
151	    ).trim();
152	    const nick = (
153	      merged.nick?.trim() ||
154	      (accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_NICK?.trim() : "") ||
155	      ""
156	    ).trim();
157	    const username = (
158	      merged.username?.trim() ||
159	      (accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_USERNAME?.trim() : "") ||
160	      nick ||
161	      "openclaw"
162	    ).trim();
163	    const realname = (
164	      merged.realname?.trim() ||
165	      (accountId === DEFAULT_ACCOUNT_ID ? process.env.IRC_REALNAME?.trim() : "") ||
166	      "OpenClaw"
167	    ).trim();
168	
169	    const passwordResolution = resolvePassword(accountId, merged);
170	    const nickserv = resolveNickServConfig(accountId, merged.nickserv);
171	
172	    const config: IrcAccountConfig = {
173	      ...merged,
174	      channels: merged.channels ?? envChannels,
175	      tls,
176	      port,
177	      host,
178	      nick,
179	      username,
180	      realname,
181	      nickserv,
182	    };
183	
184	    return {
185	      accountId,
186	      enabled,
187	      name: merged.name?.trim() || undefined,
188	      configured: Boolean(host && nick),
189	      host,
190	      port,
191	      tls,
192	      nick,
193	      username,
194	      realname,
195	      password: passwordResolution.password,
196	      passwordSource: passwordResolution.source,
197	      config,
198	    } satisfies ResolvedIrcAccount;
199	  };
200	
201	  const normalized = normalizeAccountId(params.accountId);
202	  const primary = resolve(normalized);
203	  if (hasExplicitAccountId) {
204	    return primary;
205	  }
206	  if (primary.configured) {
207	    return primary;
208	  }
209	
210	  const fallbackId = resolveDefaultIrcAccountId(params.cfg);
211	  if (fallbackId === primary.accountId) {
212	    return primary;
213	  }
214	  const fallback = resolve(fallbackId);
215	  if (!fallback.configured) {
216	    return primary;
217	  }
218	  return fallback;
219	}
