116	export async function connectIrcClient(options: IrcClientOptions): Promise<IrcClient> {
117	  const timeoutMs = options.connectTimeoutMs != null ? options.connectTimeoutMs : 15000;
118	  const messageChunkMaxChars =
119	    options.messageChunkMaxChars != null ? options.messageChunkMaxChars : 350;
120	
121	  if (!options.host.trim()) {
122	    throw new Error("IRC host is required");
123	  }
124	  if (!options.nick.trim()) {
125	    throw new Error("IRC nick is required");
126	  }
127	
128	  const desiredNick = options.nick.trim();
129	  let currentNick = desiredNick;
130	  let ready = false;
131	  let closed = false;
132	  let nickServRecoverAttempted = false;
133	  let fallbackNickAttempted = false;
134	
135	  const socket = options.tls
136	    ? tls.connect({
137	        host: options.host,
138	        port: options.port,
139	        servername: options.host,
140	      })
141	    : net.connect({ host: options.host, port: options.port });
142	
143	  socket.setEncoding("utf8");
144	
145	  let resolveReady: (() => void) | null = null;
146	  let rejectReady: ((error: Error) => void) | null = null;
147	  const readyPromise = new Promise<void>((resolve, reject) => {
148	    resolveReady = resolve;
149	    rejectReady = reject;
150	  });
151	
152	  const fail = (err: unknown) => {
153	    const error = toError(err);
154	    if (options.onError) {
155	      options.onError(error);
156	    }
157	    if (!ready && rejectReady) {
158	      rejectReady(error);
159	      rejectReady = null;
160	      resolveReady = null;
161	    }
162	  };
163	
164	  const sendRaw = (line: string) => {
165	    const cleaned = line.replace(/[\r\n]+/g, "").trim();
166	    if (!cleaned) {
167	      throw new Error("IRC command cannot be empty");
168	    }
169	    socket.write(`${cleaned}\r\n`);
170	  };
171	
172	  const tryRecoverNickCollision = (): boolean => {
173	    const nickServEnabled = options.nickserv?.enabled !== false;
174	    const nickservPassword = sanitizeIrcOutboundText(options.nickserv?.password ?? "");
175	    if (nickServEnabled && !nickServRecoverAttempted && nickservPassword) {
176	      nickServRecoverAttempted = true;
177	      try {
178	        const service = sanitizeIrcTarget(options.nickserv?.service?.trim() || "NickServ");
179	        sendRaw(`PRIVMSG ${service} :GHOST ${desiredNick} ${nickservPassword}`);
180	        sendRaw(`NICK ${desiredNick}`);
181	        return true;
182	      } catch (err) {
183	        fail(err);
184	      }
185	    }
186	
187	    if (!fallbackNickAttempted) {
188	      fallbackNickAttempted = true;
189	      const fallbackNick = buildFallbackNick(desiredNick);
190	      if (fallbackNick.toLowerCase() !== currentNick.toLowerCase()) {
191	        try {
192	          sendRaw(`NICK ${fallbackNick}`);
193	          currentNick = fallbackNick;
194	          return true;
195	        } catch (err) {
196	          fail(err);
197	        }
198	      }
199	    }
200	    return false;
201	  };
