203	  const join = (channel: string) => {
204	    const target = sanitizeIrcTarget(channel);
205	    if (!target.startsWith("#") && !target.startsWith("&")) {
206	      throw new Error(`IRC JOIN target must be a channel: ${channel}`);
207	    }
208	    sendRaw(`JOIN ${target}`);
209	  };
210	
211	  const sendPrivmsg = (target: string, text: string) => {
212	    const normalizedTarget = sanitizeIrcTarget(target);
213	    const cleaned = sanitizeIrcOutboundText(text);
214	    if (!cleaned) {
215	      return;
216	    }
217	    let remaining = cleaned;
218	    while (remaining.length > 0) {
219	      let chunk = remaining;
220	      if (chunk.length > messageChunkMaxChars) {
221	        let splitAt = chunk.lastIndexOf(" ", messageChunkMaxChars);
