### Telegram (Both Direct & Groups)
```typescript
capabilities: {
  chatTypes: ["direct", "group"],  // Both supported
  media: true,                      // Media supported
}

// Inbound routing logic
if (message.chat.type === "private") {
  // Direct message - route as DM
  peer = { kind: "direct", id: senderId };
} else {
  // Group message - route as group
  peer = { kind: "group", id: chatId, threadId };
}

// Group requires topic/thread_id support for topics
if (isForumGroup && topic) {
  threadId = `${chatId}_${topicId}`;
}
