  const normalizedSender = normalizePubkey(senderPubkey);
  for (const entry of allowFrom) {
    const normalized = normalizeNostrAllowEntry(entry);
    if (normalized === "*") {
      return true;
    }
    if (normalized === normalizedSender) {
      return true;
    }
  }
  return false;
}

