44	  runtime: DirectDmCommandAuthorizationRuntime;
45	  modeWhenAccessGroupsOff?: "allow" | "deny" | "configured";
46	  readStoreAllowFrom?: (provider: ChannelId, accountId: string) => Promise<string[]>;
47	}): Promise<ResolvedInboundDirectDmAccess> {
48	  const dmPolicy = params.dmPolicy ?? "pairing";
49	  const storeAllowFrom =
50	    dmPolicy === "pairing"
51	      ? await readStoreAllowFromForDmPolicy({
52	          provider: params.channel,
53	          accountId: params.accountId,
54	          dmPolicy,
55	          readStore: params.readStoreAllowFrom,
56	        })
57	      : [];
58	
59	  const access = resolveDmGroupAccessWithLists({
60	    isGroup: false,
61	    dmPolicy,
62	    allowFrom: params.allowFrom,
63	    storeAllowFrom,
64	    groupAllowFromFallbackToAllowFrom: false,
65	    isSenderAllowed: (allowEntries) => params.isSenderAllowed(params.senderId, allowEntries),
66	  });
67	
68	  const shouldComputeAuth = params.runtime.shouldComputeCommandAuthorized(
69	    params.rawBody,
70	    params.cfg,
71	  );
72	  const senderAllowedForCommands = params.isSenderAllowed(
73	    params.senderId,
74	    access.effectiveAllowFrom,
75	  );
76	  const commandAuthorized = shouldComputeAuth
77	    ? dmPolicy === "open"
78	      ? true
79	      : params.runtime.resolveCommandAuthorizedFromAuthorizers({
80	          useAccessGroups: params.cfg.commands?.useAccessGroups !== false,
81	          authorizers: [
82	            {
83	              configured: access.effectiveAllowFrom.length > 0,
84	              allowed: senderAllowedForCommands,
85	            },
86	          ],
87	          modeWhenAccessGroupsOff: params.modeWhenAccessGroupsOff,
88	        })
89	    : undefined;
