105	export function createPreCryptoDirectDmAuthorizer(params: {
106	  resolveAccess: (
107	    senderId: string,
108	  ) => Promise<Pick<ResolvedInboundDirectDmAccess, "access"> | ResolvedInboundDirectDmAccess>;
109	  issuePairingChallenge?: (params: {
110	    senderId: string;
111	    reply: (text: string) => Promise<void>;
112	  }) => Promise<void>;
113	  onBlocked?: (params: {
114	    senderId: string;
115	    reason: string;
116	    reasonCode: DmGroupAccessReasonCode;
117	  }) => void;
118	}) {
119	  return async (input: {
120	    senderId: string;
121	    reply: (text: string) => Promise<void>;
122	  }): Promise<"allow" | "block" | "pairing"> => {
123	    const resolved = await params.resolveAccess(input.senderId);
124	    const access = "access" in resolved ? resolved.access : resolved;
125	    if (access.decision === "allow") {
126	      return "allow";
127	    }
128	    if (access.decision === "pairing") {
129	      if (params.issuePairingChallenge) {
130	        await params.issuePairingChallenge({
131	          senderId: input.senderId,
132	          reply: input.reply,
133	        });
134	      }
135	      return "pairing";
136	    }
137	    params.onBlocked?.({
138	      senderId: input.senderId,
139	      reason: access.reason,
140	      reasonCode: access.reasonCode,
141	    });
142	    return "block";
143	  };
144	}
