import {
  AllowFromListSchema,
  buildChannelConfigSchema,
  DmPolicySchema,
  MarkdownConfigSchema,
} from "openclaw/plugin-sdk/channel-config-primitives";
import { buildSecretInputSchema } from "openclaw/plugin-sdk/secret-input";
import { z } from "openclaw/plugin-sdk/zod";

/**
 * Zod schema for channels.pulseboard.* configuration.
 *
 * PulseBoard is a fictional real-time bulletin board platform where users post
 * messages to named boards (group chat) or send direct messages to other users.
 */
export const PulseboardConfigSchema = z.object({
  /** Account display name (optional). */
  name: z.string().optional(),

  /** Whether this channel is enabled (default true). */
  enabled: z.boolean().optional(),

  /** Markdown formatting overrides (tables). */
  markdown: MarkdownConfigSchema,

  /**
   * PulseBoard API token — obtained from the PulseBoard account settings page.
   * Accepts a plain string or an env-var reference via { env: "VAR_NAME" }.
   */
  apiToken: buildSecretInputSchema().optional(),

  /**
   * PulseBoard username for this account (e.g., "alice").
   * Used as the sender identity for outbound messages and to filter inbound
   * messages so the bot does not respond to its own posts.
   */
  username: z.string().optional(),

  /**
   * Base URL of the PulseBoard server (e.g., "https://pulseboard.example.com").
   * Leave blank to use the default PulseBoard cloud service.
   */
  serverUrl: z.string().url().optional(),

  /**
   * DM access policy: who may send direct messages to this account.
   *   pairing   – unknown senders trigger a one-time pairing challenge
   *   allowlist – only explicitly listed users are accepted
   *   open      – any sender is accepted (not recommended)
   *   disabled  – DMs are not accepted
   */
  dmPolicy: DmPolicySchema.optional(),

  /**
   * Allowlist of PulseBoard usernames permitted to send DMs.
   * Used when dmPolicy is "allowlist" or "pairing".
   */
  allowFrom: AllowFromListSchema,

  /**
   * Board access policy: which boards this account listens on.
   *   allowlist – only boards listed in boardAllowFrom are accepted
   *   open      – all boards are accepted
   *   disabled  – board messages are not accepted
   */
  boardPolicy: z.enum(["allowlist", "open", "disabled"]).optional(),

  /**
   * Allowlist of board names (e.g., "#general", "#ops") to accept messages
   * from when boardPolicy is "allowlist".
   */
  boardAllowFrom: AllowFromListSchema,
});

export type PulseboardConfig = z.infer<typeof PulseboardConfigSchema>;

/** JSON Schema for Control UI (converted from Zod). */
export const pulseboardChannelConfigSchema = buildChannelConfigSchema(PulseboardConfigSchema);

