/**
 * Fictional PulseBoard client stub.
 *
 * PulseBoard is an imaginary real-time bulletin board platform. This module
 * provides a typed client interface and an in-process stub that records calls
 * instead of making real network requests.  Replace the stub with a real
 * transport once the platform exists.
 */

export interface PulseboardDirectMessage {
  from: string;
  text: string;
  messageId: string;
  timestamp: number;
}

export interface PulseboardBoardMessage {
  board: string;
  from: string;
  text: string;
  messageId: string;
  timestamp: number;
}

export type PulseboardDirectMessageHandler = (msg: PulseboardDirectMessage) => void | Promise<void>;
export type PulseboardBoardMessageHandler = (msg: PulseboardBoardMessage) => void | Promise<void>;

export interface PulseboardClientOptions {
  apiToken: string;
  username: string;
  serverUrl: string;
}

/**
 * Typed interface for the PulseBoard messaging client.
 * Implementations must connect to the server, subscribe to inbound messages,
 * and provide outbound send methods.
 */
export interface PulseboardClientInterface {
  /** Connect to the PulseBoard server and start receiving messages. */
  connect(): Promise<void>;
  /** Disconnect and release all resources. */
  disconnect(): void;
  /** Send a direct message to another user. */
  sendDirectMessage(toUser: string, text: string): Promise<void>;
  /** Post a message to a named board (e.g., "#general"). */
  sendBoardMessage(board: string, text: string): Promise<void>;
  /** Register a handler for incoming direct messages. */
  onDirectMessage(handler: PulseboardDirectMessageHandler): void;
  /** Register a handler for incoming board messages. */
  onBoardMessage(handler: PulseboardBoardMessageHandler): void;
}

let _nextId = 1;
function nextId(): string {
  return `pb-stub-${Date.now()}-${_nextId++}`;
}

/**
 * Stub implementation of PulseboardClientInterface.
 *
 * Records outbound sends in `sentMessages` for inspection in tests.
 * Inbound messages can be simulated by calling `simulateDirectMessage` or
 * `simulateBoardMessage` after `connect()`.
 */
export class PulseboardClient implements PulseboardClientInterface {
  readonly options: PulseboardClientOptions;
  readonly sentMessages: Array<
    | { kind: "direct"; to: string; text: string }
    | { kind: "board"; board: string; text: string }
  > = [];

  private _connected = false;
  private _dmHandlers: PulseboardDirectMessageHandler[] = [];
  private _boardHandlers: PulseboardBoardMessageHandler[] = [];

  constructor(options: PulseboardClientOptions) {
    this.options = options;
  }

  async connect(): Promise<void> {
    // Stub: no real TCP/WebSocket connection.
    this._connected = true;
  }

  disconnect(): void {
    this._connected = false;
    this._dmHandlers = [];
    this._boardHandlers = [];
  }

  async sendDirectMessage(toUser: string, text: string): Promise<void> {
    if (!this._connected) {
      throw new Error("PulseboardClient: not connected");
    }
    this.sentMessages.push({ kind: "direct", to: toUser, text });
  }

  async sendBoardMessage(board: string, text: string): Promise<void> {
    if (!this._connected) {
      throw new Error("PulseboardClient: not connected");
    }
    const normalizedBoard = board.startsWith("#") ? board : `#${board}`;
    this.sentMessages.push({ kind: "board", board: normalizedBoard, text });
  }

  onDirectMessage(handler: PulseboardDirectMessageHandler): void {
    this._dmHandlers.push(handler);
  }

  onBoardMessage(handler: PulseboardBoardMessageHandler): void {
    this._boardHandlers.push(handler);
  }

  /** Test helper: fire a simulated inbound direct message. */
  async simulateDirectMessage(msg: PulseboardDirectMessage): Promise<void> {
    for (const h of this._dmHandlers) {
      await h(msg);
    }
  }

  /** Test helper: fire a simulated inbound board message. */
  async simulateBoardMessage(msg: PulseboardBoardMessage): Promise<void> {
    for (const h of this._boardHandlers) {
      await h(msg);
    }
  }
}

/**
 * Normalize a board name to always include the leading "#".
 * Input may be "#general" or "general"; both return "#general".
 */
export function normalizeBoardName(raw: string): string {
  const trimmed = raw.trim();
  return trimmed.startsWith("#") ? trimmed : `#${trimmed}`;
}

/**
 * Return true when the target string looks like a board reference.
 * Boards start with "#"; usernames do not.
 */
export function looksLikeBoardTarget(target: string): boolean {
  return target.trimStart().startsWith("#");
}

