import {
  buildChannelOutboundSessionRoute,
  stripChannelTargetPrefix,
  type ChannelOutboundSessionRouteParams,
} from "openclaw/plugin-sdk/core";
import { looksLikeBoardTarget, normalizeBoardName } from "./client.js";

/**
 * Resolve the outbound session route for a PulseBoard target.
 *
 * Targets follow two conventions:
 *   - Board posts:  "#board-name" or "pulseboard:#board-name"
 *   - Direct msgs:  "username"   or "pulseboard:username"
 */
export function resolvePulseboardOutboundSessionRoute(
  params: ChannelOutboundSessionRouteParams,
) {
  const target = stripChannelTargetPrefix(params.target, "pulseboard");
  if (!target) {
    return null;
  }

  const isBoard = looksLikeBoardTarget(target);
  const normalizedTarget = isBoard ? normalizeBoardName(target) : target.trim();

  return buildChannelOutboundSessionRoute({
    cfg: params.cfg,
    agentId: params.agentId,
    channel: "pulseboard",
    accountId: params.accountId,
    peer: {
      kind: isBoard ? "group" : "direct",
      id: normalizedTarget,
    },
    chatType: isBoard ? "group" : "direct",
    from: `pulseboard:${normalizedTarget}`,
    to: `pulseboard:${normalizedTarget}`,
  });
}

