import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { createChannelPairingController } from "openclaw/plugin-sdk/channel-pairing";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  buildPassiveChannelStatusSummary,
  buildTrafficStatusSummary,
} from "openclaw/plugin-sdk/extension-shared";
import { createComputedAccountStatusAdapter } from "openclaw/plugin-sdk/status-helpers";
import {
  buildChannelConfigSchema,
  collectStatusIssuesFromLastError,
  createPreCryptoDirectDmAuthorizer,
  createDefaultChannelRuntimeState,
  dispatchInboundDirectDmWithRuntime,
  resolveInboundDirectDmAccessWithRuntime,
  type ChannelPlugin,
} from "../runtime-api.js";
import { PulseboardConfigSchema } from "./config-schema.js";
import {
  looksLikeBoardTarget,
  normalizeBoardName,
  PulseboardClient,
  type PulseboardClientInterface,
} from "./client.js";
import { getPulseboardRuntime } from "./runtime.js";
import { resolvePulseboardOutboundSessionRoute } from "./session-route.js";
import { pulseboardSetupAdapter, pulseboardSetupWizard } from "./setup-surface.js";
import {
  DEFAULT_ACCOUNT_ID,
  listPulseboardAccountIds,
  resolveDefaultPulseboardAccountId,
  resolvePulseboardAccount,
  type ResolvedPulseboardAccount,
} from "./types.js";

// Active client instances keyed by accountId.
const activeClients = new Map<string, PulseboardClientInterface>();

/** Normalize a PulseBoard allow-from entry (username or "*"). */
function normalizePulseboardAllowEntry(entry: string): string | "*" | null {
  const trimmed = entry.trim().replace(/^@/, "");
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  if (!/^[A-Za-z0-9_.-]+$/.test(trimmed)) {
    return null;
  }
  return trimmed.toLowerCase();
}

/** Return true when senderUsername is in the allowFrom list. */
function isPulseboardSenderAllowed(senderUsername: string, allowFrom: string[]): boolean {
  const normalized = senderUsername.trim().replace(/^@/, "").toLowerCase();
  for (const entry of allowFrom) {
    const e = normalizePulseboardAllowEntry(entry);
    if (e === "*") {
      return true;
    }
    if (e === normalized) {
      return true;
    }
  }
  return false;
}

async function resolvePulseboardDirectAccess(params: {
  cfg: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["cfg"];
  accountId: string;
  dmPolicy: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom: Array<string | number> | undefined;
  senderUsername: string;
  rawBody: string;
  runtime: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["runtime"];
}) {
  return resolveInboundDirectDmAccessWithRuntime({
    cfg: params.cfg,
    channel: "pulseboard",
    accountId: params.accountId,
    dmPolicy: params.dmPolicy,
    allowFrom: params.allowFrom,
    senderId: params.senderUsername,
    rawBody: params.rawBody,
    isSenderAllowed: isPulseboardSenderAllowed,
    runtime: params.runtime,
    modeWhenAccessGroupsOff: "configured",
  });
}

const resolvePulseboardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseboardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  normalizeEntry: (raw) => normalizePulseboardAllowEntry(raw) ?? raw.trim(),
});

const pulseboardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseboardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseboardAccount({ cfg }),
  listAccountIds: listPulseboardAccountIds,
  defaultAccountId: resolveDefaultPulseboardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "apiToken", "username", "serverUrl", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((e) => String(e).trim().replace(/^@/, ""))
      .filter(Boolean)
      .map((e) => normalizePulseboardAllowEntry(e) ?? e)
      .filter(Boolean),
});

export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount> = createChatChannelPlugin(
  {
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Real-time bulletin board messaging (boards + DMs)",
        order: 75,
      },
      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: buildChannelConfigSchema(PulseboardConfigSchema),
      setup: pulseboardSetupAdapter,
      setupWizard: pulseboardSetupWizard,
      config: {
        ...pulseboardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              username: account.username,
              serverUrl: account.serverUrl,
            },
          }),
      },
      messaging: {
        normalizeTarget: (target) => {
          const t = target.trim();
          return looksLikeBoardTarget(t) ? normalizeBoardName(t) : t;
        },
        targetResolver: {
          looksLikeId: (input) => {
            const t = input.trim();
            return looksLikeBoardTarget(t) || /^[A-Za-z0-9_.-]+$/.test(t);
          },
          hint: "<#board-name|username>",
        },
        resolveOutboundSessionRoute: (params) =>
          resolvePulseboardOutboundSessionRoute(params),
      },
      status: {
        ...createComputedAccountStatusAdapter<ResolvedPulseboardAccount>({
          defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
          collectStatusIssues: (accounts) =>
            collectStatusIssuesFromLastError("pulseboard", accounts),
          buildChannelSummary: ({ snapshot }) =>
            buildPassiveChannelStatusSummary(snapshot, {
              username: snapshot.username ?? null,
            }),
          resolveAccountSnapshot: ({ account, runtime }) => ({
            accountId: account.accountId,
            name: account.name,
            enabled: account.enabled,
            configured: account.configured,
            extra: {
              username: account.username,
              serverUrl: account.serverUrl,
              ...buildTrafficStatusSummary(runtime),
            },
          }),
        }),
      },
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          ctx.setStatus({
            accountId: account.accountId,
            username: account.username,
          });
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (user: ${account.username})`,
          );

          if (!account.configured) {
            throw new Error(
              "PulseBoard is not configured (need apiToken and username in channels.pulseboard).",
            );
          }

          const runtime = getPulseboardRuntime();
          const pairing = createChannelPairingController({
            core: runtime,
            channel: "pulseboard",
            accountId: account.accountId,
          });

          const resolveInboundDmAccess = async (senderUsername: string, rawBody: string) =>
            await resolvePulseboardDirectAccess({
              cfg: ctx.cfg,
              accountId: account.accountId,
              dmPolicy: account.config.dmPolicy ?? "pairing",
              allowFrom: account.config.allowFrom,
              senderUsername,
              rawBody,
              runtime: {
                shouldComputeCommandAuthorized:
                  runtime.channel.commands.shouldComputeCommandAuthorized,
                resolveCommandAuthorizedFromAuthorizers:
                  runtime.channel.commands.resolveCommandAuthorizedFromAuthorizers,
              },
            });

          const authorizeSender = createPreCryptoDirectDmAuthorizer({
            resolveAccess: async (senderUsername) =>
              await resolveInboundDmAccess(senderUsername, ""),
            issuePairingChallenge: async ({ senderId, reply }) => {
              await pairing.issueChallenge({
                senderId,
                senderIdLine: `Your PulseBoard username: ${senderId}`,
                sendPairingReply: reply,
                onCreated: () => {
                  ctx.log?.debug?.(
                    `[${account.accountId}] pulseboard pairing request sender=${senderId}`,
                  );
                },
                onReplyError: (err) => {
                  ctx.log?.warn?.(
                    `[${account.accountId}] pulseboard pairing reply failed for ${senderId}: ${String(err)}`,
                  );
                },
              });
            },
            onBlocked: ({ senderId, reason }) => {
              ctx.log?.debug?.(
                `[${account.accountId}] blocked PulseBoard sender ${senderId} (${reason})`,
              );
            },
          });

          const client = new PulseboardClient({
            apiToken: account.apiToken,
            username: account.username,
            serverUrl: account.serverUrl,
          });

          await client.connect();
          activeClients.set(account.accountId, client);

          ctx.log?.info(
            `[${account.accountId}] PulseBoard client connected (server: ${account.serverUrl})`,
          );

          // Handle incoming direct messages.
          client.onDirectMessage(async (msg) => {
            // Ignore messages sent by this account.
            if (msg.from.toLowerCase() === account.username.toLowerCase()) {
              return;
            }

            const authorized = await authorizeSender({
              senderId: msg.from,
              reply: async (text) => {
                await client.sendDirectMessage(msg.from, text);
              },
            });
            if (!authorized) {
              return;
            }

            const resolvedAccess = await resolveInboundDmAccess(msg.from, msg.text);
            if (resolvedAccess.access.decision !== "allow") {
              ctx.log?.warn?.(
                `[${account.accountId}] dropping PulseBoard DM after preflight drift (${msg.from}, ${resolvedAccess.access.reason})`,
              );
              return;
            }

            await dispatchInboundDirectDmWithRuntime({
              cfg: ctx.cfg,
              runtime,
              channel: "pulseboard",
              channelLabel: "PulseBoard",
              accountId: account.accountId,
              peer: { kind: "direct", id: msg.from },
              senderId: msg.from,
              senderAddress: `pulseboard:${msg.from}`,
              recipientAddress: `pulseboard:${account.username}`,
              conversationLabel: msg.from,
              rawBody: msg.text,
              messageId: msg.messageId,
              timestamp: msg.timestamp,
              commandAuthorized: resolvedAccess.commandAuthorized,
              deliver: async (payload) => {
                const text =
                  payload && typeof payload === "object" && "text" in payload
                    ? String((payload as { text?: string }).text ?? "")
                    : "";
                if (!text.trim()) {
                  return;
                }
                const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                  cfg: ctx.cfg,
                  channel: "pulseboard",
                  accountId: account.accountId,
                });
                await client.sendDirectMessage(
                  msg.from,
                  runtime.channel.text.convertMarkdownTables(text, tableMode),
                );
              },
              onRecordError: (err) => {
                ctx.log?.error?.(
                  `[${account.accountId}] failed recording PulseBoard DM session: ${String(err)}`,
                );
              },
              onDispatchError: (err, info) => {
                ctx.log?.error?.(
                  `[${account.accountId}] PulseBoard DM ${info.kind} reply failed: ${String(err)}`,
                );
              },
            });
          });

          // Handle incoming board messages.
          client.onBoardMessage(async (msg) => {
            // Ignore messages posted by this account.
            if (msg.from.toLowerCase() === account.username.toLowerCase()) {
              return;
            }

            // Apply board access policy.
            const boardPolicy = account.config.boardPolicy ?? "open";
            if (boardPolicy === "disabled") {
              ctx.log?.debug?.(
                `[${account.accountId}] pulseboard: board messages disabled, dropping ${msg.board}`,
              );
              return;
            }
            if (boardPolicy === "allowlist") {
              const boardAllowFrom = (account.config.boardAllowFrom ?? []).map((e) =>
                String(e)
                  .trim()
                  .replace(/^#/, ""),
              );
              const normalizedBoard = msg.board.replace(/^#/, "").toLowerCase();
              const isAllowed = boardAllowFrom.some(
                (b) => b === "*" || b.toLowerCase() === normalizedBoard,
              );
              if (!isAllowed) {
                ctx.log?.debug?.(
                  `[${account.accountId}] pulseboard: board ${msg.board} not in allowlist`,
                );
                return;
              }
            }

            // Board messages do not go through pairing; anyone may post to a board.
            // Use extraContext to set ChatType = "group" since the helper hardcodes "direct".
            await dispatchInboundDirectDmWithRuntime({
              cfg: ctx.cfg,
              runtime,
              channel: "pulseboard",
              channelLabel: "PulseBoard",
              accountId: account.accountId,
              peer: { kind: "group", id: msg.board },
              senderId: msg.from,
              senderAddress: `pulseboard:${msg.from}`,
              recipientAddress: `pulseboard:${msg.board}`,
              conversationLabel: `${msg.board} / ${msg.from}`,
              rawBody: msg.text,
              messageId: msg.messageId,
              timestamp: msg.timestamp,
              // Override ChatType so the AI context reflects a group conversation.
              extraContext: {
                ChatType: "group",
                GroupSubject: msg.board,
                SenderName: msg.from,
              },
              deliver: async (payload) => {
                const text =
                  payload && typeof payload === "object" && "text" in payload
                    ? String((payload as { text?: string }).text ?? "")
                    : "";
                if (!text.trim()) {
                  return;
                }
                const tableMode = runtime.channel.text.resolveMarkdownTableMode({
                  cfg: ctx.cfg,
                  channel: "pulseboard",
                  accountId: account.accountId,
                });
                await client.sendBoardMessage(
                  msg.board,
                  runtime.channel.text.convertMarkdownTables(text, tableMode),
                );
              },
              onRecordError: (err) => {
                ctx.log?.error?.(
                  `[${account.accountId}] failed recording PulseBoard board session: ${String(err)}`,
                );
              },
              onDispatchError: (err, info) => {
                ctx.log?.error?.(
                  `[${account.accountId}] PulseBoard board ${info.kind} reply failed: ${String(err)}`,
                );
              },
            });
          });

          // Return cleanup function.
          return {
            stop: () => {
              client.disconnect();
              activeClients.delete(account.accountId);
              ctx.log?.info(`[${account.accountId}] PulseBoard provider stopped`);
            },
          };
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseboardUser",
        message: "Your pairing request has been approved!",
        normalizeAllowEntry: (entry) => normalizePulseboardAllowEntry(entry) ?? entry.trim(),
        notify: async ({ id, message }) => {
          const client = activeClients.get(DEFAULT_ACCOUNT_ID);
          if (client) {
            await client.sendDirectMessage(id, message);
          }
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseboardDmPolicy,
    },
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ cfg, to, text, accountId }) => {
        const aid = accountId ?? DEFAULT_ACCOUNT_ID;
        const client = activeClients.get(aid);
        if (!client) {
          throw new Error(`PulseBoard client not running for account ${aid}`);
        }
        const core = getPulseboardRuntime();
        const tableMode = core.channel.text.resolveMarkdownTableMode({
          cfg,
          channel: "pulseboard",
          accountId: aid,
        });
        const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);

        if (looksLikeBoardTarget(to)) {
          const board = normalizeBoardName(to);
          await client.sendBoardMessage(board, message);
          return attachChannelToResult("pulseboard", {
            to: board,
            messageId: `pulseboard-${Date.now()}`,
          });
        }

        await client.sendDirectMessage(to, message);
        return attachChannelToResult("pulseboard", {
          to,
          messageId: `pulseboard-${Date.now()}`,
        });
      },
    },
  },
);

/**
 * Get the active PulseBoard client for an account.
 * Returns undefined when the provider is not running.
 */
export function getActivePulseboardClient(
  accountId: string = DEFAULT_ACCOUNT_ID,
): PulseboardClientInterface | undefined {
  return activeClients.get(accountId);
}

