import { describe, expect, it } from "vitest";
import {
  looksLikeBoardTarget,
  normalizeBoardName,
  PulseboardClient,
} from "./client.js";
import {
  listPulseboardAccountIds,
  resolvePulseboardAccount,
  DEFAULT_ACCOUNT_ID,
  DEFAULT_SERVER_URL,
} from "./types.js";
import type { OpenClawConfig } from "../api.js";

// ---------------------------------------------------------------------------
// client helpers
// ---------------------------------------------------------------------------

describe("normalizeBoardName", () => {
  it("adds # when missing", () => {
    expect(normalizeBoardName("general")).toBe("#general");
  });

  it("keeps existing # prefix", () => {
    expect(normalizeBoardName("#ops")).toBe("#ops");
  });

  it("trims whitespace before normalizing", () => {
    expect(normalizeBoardName("  announce  ")).toBe("#announce");
  });
});

describe("looksLikeBoardTarget", () => {
  it("returns true for board targets", () => {
    expect(looksLikeBoardTarget("#general")).toBe(true);
    expect(looksLikeBoardTarget(" #ops")).toBe(true);
  });

  it("returns false for usernames", () => {
    expect(looksLikeBoardTarget("alice")).toBe(false);
    expect(looksLikeBoardTarget("bob123")).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// PulseboardClient stub
// ---------------------------------------------------------------------------

describe("PulseboardClient (stub)", () => {
  it("records sent direct messages", async () => {
    const client = new PulseboardClient({
      apiToken: "tok-test",
      username: "testbot",
      serverUrl: DEFAULT_SERVER_URL,
    });
    await client.connect();
    await client.sendDirectMessage("alice", "Hello!");
    expect(client.sentMessages).toEqual([{ kind: "direct", to: "alice", text: "Hello!" }]);
    client.disconnect();
  });

  it("records sent board messages with # prefix", async () => {
    const client = new PulseboardClient({
      apiToken: "tok-test",
      username: "testbot",
      serverUrl: DEFAULT_SERVER_URL,
    });
    await client.connect();
    await client.sendBoardMessage("general", "Hello board!");
    expect(client.sentMessages).toEqual([
      { kind: "board", board: "#general", text: "Hello board!" },
    ]);
    client.disconnect();
  });

  it("preserves # when already present", async () => {
    const client = new PulseboardClient({
      apiToken: "tok-test",
      username: "testbot",
      serverUrl: DEFAULT_SERVER_URL,
    });
    await client.connect();
    await client.sendBoardMessage("#ops", "ping");
    expect(client.sentMessages[0]).toMatchObject({ board: "#ops" });
    client.disconnect();
  });

  it("throws when sending while disconnected", async () => {
    const client = new PulseboardClient({
      apiToken: "tok-test",
      username: "testbot",
      serverUrl: DEFAULT_SERVER_URL,
    });
    await expect(client.sendDirectMessage("alice", "hi")).rejects.toThrow("not connected");
  });

  it("delivers simulated direct messages to registered handlers", async () => {
    const client = new PulseboardClient({
      apiToken: "tok-test",
      username: "testbot",
      serverUrl: DEFAULT_SERVER_URL,
    });
    await client.connect();
    const received: string[] = [];
    client.onDirectMessage((msg) => {
      received.push(msg.text);
    });
    await client.simulateDirectMessage({
      from: "alice",
      text: "hey bot",
      messageId: "msg-1",
      timestamp: 1_700_000_000_000,
    });
    expect(received).toEqual(["hey bot"]);
    client.disconnect();
  });

  it("delivers simulated board messages to registered handlers", async () => {
    const client = new PulseboardClient({
      apiToken: "tok-test",
      username: "testbot",
      serverUrl: DEFAULT_SERVER_URL,
    });
    await client.connect();
    const boards: string[] = [];
    client.onBoardMessage((msg) => {
      boards.push(msg.board);
    });
    await client.simulateBoardMessage({
      board: "#general",
      from: "bob",
      text: "hello board",
      messageId: "msg-2",
      timestamp: 1_700_000_001_000,
    });
    expect(boards).toEqual(["#general"]);
    client.disconnect();
  });
});

