} from "./types.js";

// Active client instances keyed by accountId.
const activeClients = new Map<string, PulseboardClientInterface>();

/** Normalize a PulseBoard allow-from entry (username or "*"). */
function normalizePulseboardAllowEntry(entry: string): string | "*" | null {
  const trimmed = entry.trim().replace(/^@/, "");
  if (!trimmed) {
    return null;
  }
  if (trimmed === "*") {
    return "*";
  }
  if (!/^[A-Za-z0-9_.-]+$/.test(trimmed)) {
    return null;
  }
  return trimmed.toLowerCase();
}

/** Return true when senderUsername is in the allowFrom list. */
function isPulseboardSenderAllowed(senderUsername: string, allowFrom: string[]): boolean {
  const normalized = senderUsername.trim().replace(/^@/, "").toLowerCase();
  for (const entry of allowFrom) {
    const e = normalizePulseboardAllowEntry(entry);
    if (e === "*") {
      return true;
    }
    if (e === normalized) {
      return true;
    }
  }
  return false;
}

async function resolvePulseboardDirectAccess(params: {
  cfg: Parameters<typeof resolveInboundDirectDmAccessWithRuntime>[0]["cfg"];
