              peer: { kind: "group", id: msg.board },
              senderId: msg.from,
              senderAddress: `pulseboard:${msg.from}`,
              recipientAddress: `pulseboard:${msg.board}`,
              conversationLabel: `${msg.board} / ${msg.from}`,
              rawBody: msg.text,
              messageId: msg.messageId,
              timestamp: msg.timestamp,
