                ctx.log?.error?.(
                  `[${account.accountId}] failed recording PulseBoard board session: ${String(err)}`,
                );
              },
              onDispatchError: (err, info) => {
                ctx.log?.error?.(
                  `[${account.accountId}] PulseBoard board ${info.kind} reply failed: ${String(err)}`,
                );
              },
            });
          });

          // Return cleanup function.
          return {
            stop: () => {
              client.disconnect();
