import type { ChannelSetupAdapter } from "openclaw/plugin-sdk/channel-setup";
import { DEFAULT_ACCOUNT_ID } from "openclaw/plugin-sdk/account-id";
import {
  hasConfiguredSecretInput,
  normalizeSecretInputString,
} from "openclaw/plugin-sdk/secret-input";
import {
  createTopLevelChannelParsedAllowFromPrompt,
  createTopLevelChannelDmPolicy,
  createStandardChannelSetupStatus,
  mergeAllowFromEntries,
  parseSetupEntriesWithParser,
  patchTopLevelChannelConfigSection,
} from "openclaw/plugin-sdk/setup";
import type { ChannelSetupDmPolicy, ChannelSetupWizard } from "openclaw/plugin-sdk/setup";
import { formatDocsLink } from "openclaw/plugin-sdk/setup";
import { resolvePulseboardAccount } from "./types.js";

const channel = "pulseboard" as const;

const PULSEBOARD_SETUP_HELP_LINES = [
  "Obtain your API token from the PulseBoard account settings page.",
  "Your username is the PulseBoard handle you log in with (e.g., alice).",
  "Server URL is optional; leave blank to use the PulseBoard cloud service.",
  "Env vars supported: PULSEBOARD_API_TOKEN and PULSEBOARD_USERNAME.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

const PULSEBOARD_ALLOW_FROM_HELP_LINES = [
  "Allowlist PulseBoard DMs by username.",
  "Examples:",
  "- alice",
  "- bob",
  "Multiple entries: comma-separated.",
  `Docs: ${formatDocsLink("/channels/pulseboard", "channels/pulseboard")}`,
];

function parsePulseboardAllowFrom(raw: string): { entries: string[]; error?: string } {
  return parseSetupEntriesWithParser(raw, (entry) => {
    const cleaned = entry.trim().replace(/^@/, "");
    if (!cleaned || !/^[A-Za-z0-9_.-]+$/.test(cleaned)) {
      return { error: `Invalid PulseBoard username: ${entry}` };
    }
    return { value: cleaned };
  });
}

const promptPulseboardAllowFrom = createTopLevelChannelParsedAllowFromPrompt({
  channel,
  defaultAccountId: DEFAULT_ACCOUNT_ID,
  noteTitle: "PulseBoard DM allowlist",
  noteLines: PULSEBOARD_ALLOW_FROM_HELP_LINES,
  message: "PulseBoard allowFrom",
  placeholder: "alice, bob",
  parseEntries: parsePulseboardAllowFrom,
  mergeEntries: ({ existing, parsed }) => mergeAllowFromEntries(existing, parsed),
});

const pulseboardDmPolicy: ChannelSetupDmPolicy = createTopLevelChannelDmPolicy({
  label: "PulseBoard",
  channel,
  policyKey: "channels.pulseboard.dmPolicy",
  allowFromKey: "channels.pulseboard.allowFrom",
  getCurrent: (cfg) => cfg.channels?.pulseboard?.dmPolicy ?? "pairing",
  promptAllowFrom: promptPulseboardAllowFrom,
});

export const pulseboardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
  applyAccountName: ({ cfg, name }) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: name?.trim() ? { name: name.trim() } : {},
    }),
  validateInput: ({ input }) => {
    // inputKey mappings: token=apiToken, userId=username, url=serverUrl
    const typedInput = input as {
      useEnv?: boolean;
      token?: string;
      userId?: string;
      url?: string;
    };
    if (!typedInput.useEnv) {
      if (!typedInput.token?.trim()) {
        return "PulseBoard requires --token (API token) or --use-env.";
      }
      if (!typedInput.userId?.trim()) {
        return "PulseBoard requires --user-id (username).";
      }
    }
    if (typedInput.url?.trim()) {
      try {
        new URL(typedInput.url.trim());
      } catch {
        return "Server URL must be a valid https:// URL.";
      }
    }
    return null;
  },
  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as {
      useEnv?: boolean;
      token?: string;
      userId?: string;
      url?: string;
    };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel,
      enabled: true,
      clearFields: typedInput.useEnv ? ["apiToken"] : undefined,
      patch: {
        ...(typedInput.useEnv ? {} : { apiToken: typedInput.token?.trim() }),
        ...(typedInput.userId?.trim() ? { username: typedInput.userId.trim() } : {}),
        ...(typedInput.url?.trim() ? { serverUrl: typedInput.url.trim() } : {}),
      },
    });
  },
};

export const pulseboardSetupWizard: ChannelSetupWizard = {
  channel,
  resolveAccountIdForConfigure: () => DEFAULT_ACCOUNT_ID,
  resolveShouldPromptAccountIds: () => false,
  status: createStandardChannelSetupStatus({
    channelLabel: "PulseBoard",
    configuredLabel: "configured",
    unconfiguredLabel: "needs API token and username",
    configuredHint: "configured",
    unconfiguredHint: "needs API token and username",
    configuredScore: 1,
    unconfiguredScore: 0,
    includeStatusLine: true,
    resolveConfigured: ({ cfg }) => resolvePulseboardAccount({ cfg }).configured,
    resolveExtraStatusLines: ({ cfg }) => {
      const account = resolvePulseboardAccount({ cfg });
      return account.configured
        ? [`Username: ${account.username}`, `Server: ${account.serverUrl}`]
        : [];
    },
  }),
  introNote: {
    title: "PulseBoard setup",
    lines: PULSEBOARD_SETUP_HELP_LINES,
  },
  envShortcut: {
    prompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
    preferredEnvVar: "PULSEBOARD_API_TOKEN",
    isAvailable: ({ cfg, accountId }) =>
      accountId === DEFAULT_ACCOUNT_ID &&
      Boolean(process.env.PULSEBOARD_API_TOKEN?.trim()) &&
      !hasConfiguredSecretInput(resolvePulseboardAccount({ cfg, accountId }).config.apiToken),
    apply: async ({ cfg }) =>
      patchTopLevelChannelConfigSection({
        cfg,
        channel,
        enabled: true,
        clearFields: ["apiToken"],
        patch: {},
      }),
  },
  credentials: [
    {
      // "token" is the ChannelSetupInput key; maps to channels.pulseboard.apiToken
      inputKey: "token",
      providerHint: channel,
      credentialLabel: "API token",
      preferredEnvVar: "PULSEBOARD_API_TOKEN",
      helpTitle: "PulseBoard API token",
      helpLines: PULSEBOARD_SETUP_HELP_LINES,
      envPrompt: "PULSEBOARD_API_TOKEN detected. Use env var?",
      keepPrompt: "PulseBoard API token already configured. Keep it?",
      inputPrompt: "PulseBoard API token",
      allowEnv: ({ accountId }) => accountId === DEFAULT_ACCOUNT_ID,
      inspect: ({ cfg, accountId }) => {
        const account = resolvePulseboardAccount({ cfg, accountId });
        return {
          accountConfigured: account.configured,
          hasConfiguredValue: hasConfiguredSecretInput(account.config.apiToken),
          resolvedValue: normalizeSecretInputString(account.config.apiToken),
          envValue: process.env.PULSEBOARD_API_TOKEN?.trim(),
        };
      },
      applyUseEnv: async ({ cfg }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: ["apiToken"],
          patch: {},
        }),
      applySet: async ({ cfg, resolvedValue }) =>
        patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { apiToken: resolvedValue },
        }),
    },
  ],
  textInputs: [
    {
      // "userId" is the ChannelSetupInput key; maps to channels.pulseboard.username
      inputKey: "userId",
      message: "PulseBoard username",
      placeholder: "alice",
      required: true,
      applyEmptyValue: false,
      helpTitle: "PulseBoard username",
      helpLines: ["Your PulseBoard handle (e.g., alice). No @ prefix required."],
      currentValue: ({ cfg, accountId }) =>
        resolvePulseboardAccount({ cfg, accountId }).username,
      keepPrompt: (value) => `Username set to "${value}". Keep it?`,
      validate: ({ value }) => {
        const cleaned = value.trim().replace(/^@/, "");
        if (!cleaned) {
          return "Username is required.";
        }
        if (!/^[A-Za-z0-9_.-]+$/.test(cleaned)) {
          return "Username may only contain letters, digits, underscores, hyphens, and dots.";
        }
        return undefined;
      },
      applySet: async ({ cfg, value }) => {
        const cleaned = value.trim().replace(/^@/, "");
        return patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          patch: { username: cleaned },
        });
      },
    },
    {
      // "url" is the ChannelSetupInput key; maps to channels.pulseboard.serverUrl
      inputKey: "url",
      message: "PulseBoard server URL (optional)",
      placeholder: "https://pulseboard.example.com",
      required: false,
      applyEmptyValue: true,
      helpTitle: "PulseBoard server URL",
      helpLines: ["Leave blank to use the PulseBoard cloud service."],
      currentValue: ({ cfg, accountId }) => {
        const account = resolvePulseboardAccount({ cfg, accountId });
        // Only show the stored value, not the built-in default.
        return account.config.serverUrl?.trim() ?? "";
      },
      keepPrompt: (value) => `Server URL set to "${value}". Keep it?`,
      validate: ({ value }) => {
        if (!value.trim()) {
          return undefined;
        }
        try {
          new URL(value.trim());
          return undefined;
        } catch {
          return "Server URL must be a valid https:// URL.";
        }
      },
      applySet: async ({ cfg, value }) => {
        const trimmed = value.trim();
        return patchTopLevelChannelConfigSection({
          cfg,
          channel,
          enabled: true,
          clearFields: trimmed ? undefined : ["serverUrl"],
          patch: trimmed ? { serverUrl: trimmed } : {},
        });
      },
    },
  ],
  dmPolicy: pulseboardDmPolicy,
  disable: (cfg) =>
    patchTopLevelChannelConfigSection({
      cfg,
      channel,
      patch: { enabled: false },
    }),
};

